class Solution:
    def countOfAtoms(self, formula: str) -> str:
        stack = [{}]
        i = 0
        while i < len(formula):
            if formula[i] == '(':
                stack.append({})
                i += 1
            elif formula[i] == ')':
                i += 1
                count = 0
                while i < len(formula) and formula[i].isdigit():
                    count = count * 10 + int(formula[i])
                    i += 1
                for atom in stack.pop():
                    stack[-1][atom] = stack[-1].get(atom, 0) + stack.pop(atom) * count
            else:
                atom = ''
                while i < len(formula) and formula[i].isupper():
                    atom += formula[i]
                    i += 1
                count = 0
                while i < len(formula) and formula[i].isdigit():
                    count = count * 10 + int(formula[i])
                    i += 1
                if count == 0:
                    count = 1
                stack[-1][atom] = stack[-1].get(atom, 0) + count
        res = []
        for atom, count in sorted(stack[-1].items()):
            if count > 1:
                res.append(atom + str(count))
            else:
                res.append(atom)
        return ''.join(res)
